import React from "react";
import { Link } from "react-router-dom";
import { useApp } from "../context/AppContext";
import "./WishlistPage.css"; // Use the CSS I provided in the previous message

const WishlistPage = () => {
  // Pull wishlist and functions directly from your context!
  const { wishlist, removeFromWishlist, addToCart } = useApp();

  return (
    <div className="wishlist-page">
      <header className="wishlist-header">
        <h1>My Wishlist</h1>
        <span className="item-count">
          {wishlist.length} {wishlist.length === 1 ? "Item" : "Items"}
        </span>
      </header>

      {wishlist.length === 0 ? (
        <div className="empty-wishlist">
          <div className="empty-icon">♡</div>
          <h2>Your wishlist is currently empty</h2>
          <p>Explore our store and add items you love to your wishlist!</p>
          <Link to="/">
            <button className="continue-shopping-btn">Continue Shopping</button>
          </Link>
        </div>
      ) : (
        <div className="wishlist-grid">
          {wishlist.map((product) => (
            <div key={product.id} className="wishlist-card">
              <div className="card-image-container">
                <img
                  src={product.image}
                  alt={product.name}
                  className="product-image"
                />
                <button
                  className="remove-btn"
                  onClick={() => removeFromWishlist(product.id)} // Your context function
                  title="Remove from wishlist"
                >
                  ✕
                </button>
              </div>

              <div className="card-details">
                <h3 className="product-name">{product.name}</h3>
                <p className="product-price">${product.price}</p>

                <button
                  className="add-to-cart-btn"
                  onClick={() => addToCart(product)} // Your context function
                >
                  Add to Cart
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default WishlistPage;
